import{_ as e,c as i,a0 as n,o as t}from"./chunks/framework.B6JXc2q-.js";const h=JSON.parse('{"title":"Runtime 架构（Runtime Architecture）","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/runtime_architecture.md","filePath":"architecture/runtime_architecture.md"}'),c={name:"architecture/runtime_architecture.md"};function s(o,a,r,l,d,p){return t(),i("div",null,a[0]||(a[0]=[n(`<h1 id="runtime-架构-runtime-architecture" tabindex="-1">Runtime 架构（Runtime Architecture） <a class="header-anchor" href="#runtime-架构-runtime-architecture" aria-label="Permalink to &quot;Runtime 架构（Runtime Architecture）&quot;">​</a></h1><p>版本：v1.0 状态：正式架构文档 最后更新：2026-03-28</p><p>本文档说明 runtime 在系统中的地位、内部构成、生命周期与和其他边界的关系。HTTP 接口规范见 <code>docs/api/api_v1_spec.md</code>，core 层技术规范见 <code>docs/spec/runtime_specification.md</code>。</p><hr><h2 id="_1-runtime-的职责边界" tabindex="-1">1. Runtime 的职责边界 <a class="header-anchor" href="#_1-runtime-的职责边界" aria-label="Permalink to &quot;1. Runtime 的职责边界&quot;">​</a></h2><p><strong>runtime</strong> 是系统的主协调对象，由 <code>XiaoMusic</code> 类（<code>xiaomusic/xiaomusic.py</code>）承载。其职责是：</p><ul><li>创建并持有各子系统的实例（auth、config、device、music_library 等）</li><li>管理各子系统的启动顺序与依赖注入</li><li>响应配置变更、设备上下线等系统级事件</li><li>为 API 层提供运行时上下文（通过 <code>runtime_provider</code>）</li></ul><p>runtime <strong>不负责</strong>：</p><ul><li>HTTP 路由（由 <code>api</code> 层负责）</li><li>媒体来源解析（由 <code>source</code> 层负责）</li><li>播放策略与队列编排（由 <code>playback</code> 层的 <code>facade.py</code> / <code>coordinator</code> 负责）</li><li>设备命令的具体执行（由 <code>device</code> 层负责）</li><li>状态快照构建（由 <code>playback/facade.py</code> 的 <code>build_player_state_snapshot()</code> 负责）</li></ul><hr><h2 id="_2-runtime-与其他边界的关系" tabindex="-1">2. Runtime 与其他边界的关系 <a class="header-anchor" href="#_2-runtime-与其他边界的关系" aria-label="Permalink to &quot;2. Runtime 与其他边界的关系&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>runtime (XiaoMusic)</span></span>
<span class="line"><span>    ├── 持有 → config (Config / ConfigManager)</span></span>
<span class="line"><span>    ├── 持有 → auth (AuthManager)</span></span>
<span class="line"><span>    ├── 持有 → device (DeviceManager → DevicePlayer × N)</span></span>
<span class="line"><span>    ├── 持有 → music_library (MusicLibrary)</span></span>
<span class="line"><span>    ├── 持有 → link_playback_strategy (LinkPlaybackStrategy)</span></span>
<span class="line"><span>    ├── 订阅 → event_bus (EventBus)</span></span>
<span class="line"><span>    └── 注入到 → api 层 (通过 runtime_provider / dependencies.py)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>api 层</span></span>
<span class="line"><span>    └── 通过 facade (PlaybackFacade) 调用 playback 核心</span></span>
<span class="line"><span>        ├── facade 从 runtime_provider 获取 XiaoMusic 实例</span></span>
<span class="line"><span>        └── facade 构建 PlaybackCoordinator 执行播放链</span></span>
<span class="line"><span></span></span>
<span class="line"><span>relay</span></span>
<span class="line"><span>    └── 独立运行，runtime 提供配置，relay 不反向依赖 runtime</span></span></code></pre></div><p><strong>关键约束：</strong></p><ul><li><code>api</code> 层通过 <code>dependencies.py</code> 中的 <code>_get_facade()</code> / <code>_get_xiaomusic()</code> 访问 runtime，不直接 import <code>XiaoMusic</code> 实例</li><li><code>playback/facade.py</code> 是 api 层调用播放能力的唯一入口，不得绕过 facade 直接调用 coordinator 或 transport</li><li>runtime 不直接响应 HTTP 请求，所有 HTTP 请求必须经过 <code>api</code> 层</li></ul><hr><h2 id="_3-runtime-生命周期" tabindex="-1">3. Runtime 生命周期 <a class="header-anchor" href="#_3-runtime-生命周期" aria-label="Permalink to &quot;3. Runtime 生命周期&quot;">​</a></h2><h3 id="_3-1-启动阶段" tabindex="-1">3.1 启动阶段 <a class="header-anchor" href="#_3-1-启动阶段" aria-label="Permalink to &quot;3.1 启动阶段&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 读取配置（ConfigManager.try_init_setting）</span></span>
<span class="line"><span>2. 初始化音乐库（MusicLibrary.gen_all_music_list）</span></span>
<span class="line"><span>3. 初始化设备管理器（DeviceManager）</span></span>
<span class="line"><span>4. 初始化认证管理器（AuthManager）</span></span>
<span class="line"><span>5. 注册事件监听（EventBus）</span></span>
<span class="line"><span>6. 启动 FastAPI 应用（包含 relay、API 路由）</span></span>
<span class="line"><span>7. auth_manager.init_all_data()  ← 建立小米账号连接</span></span>
<span class="line"><span>8. 启动 keepalive 循环（auth_manager.keepalive_loop）</span></span>
<span class="line"><span>9. 进入 ready 状态</span></span></code></pre></div><h3 id="_3-2-ready-状态" tabindex="-1">3.2 Ready 状态 <a class="header-anchor" href="#_3-2-ready-状态" aria-label="Permalink to &quot;3.2 Ready 状态&quot;">​</a></h3><ul><li>所有子系统正常运行</li><li>API 层可正常响应请求</li><li>SSE 状态推送正常工作</li></ul><h3 id="_3-3-degraded-状态" tabindex="-1">3.3 Degraded 状态 <a class="header-anchor" href="#_3-3-degraded-状态" aria-label="Permalink to &quot;3.3 Degraded 状态&quot;">​</a></h3><p>当以下任一情况发生时，系统进入降级状态，但不停止服务：</p><ul><li>认证失效（<code>auth locked</code>）：设备相关 API 返回错误，其他 API 正常</li><li>设备离线：该设备的播放 API 返回 <code>E_DEVICE_NOT_FOUND</code></li><li>音乐库刷新失败：使用上次成功的库数据</li></ul><h3 id="_3-4-配置变更" tabindex="-1">3.4 配置变更 <a class="header-anchor" href="#_3-4-配置变更" aria-label="Permalink to &quot;3.4 配置变更&quot;">​</a></h3><p>通过 <code>EventBus</code> 的 <code>CONFIG_CHANGED</code> / <code>DEVICE_CONFIG_CHANGED</code> 事件触发各子系统的配置重载。配置变更不重启进程，只触发受影响子系统的局部刷新。</p><h3 id="_3-5-关闭" tabindex="-1">3.5 关闭 <a class="header-anchor" href="#_3-5-关闭" aria-label="Permalink to &quot;3.5 关闭&quot;">​</a></h3><p>各子系统按启动的逆序清理资源（关闭设备连接、停止 keepalive、释放 relay session 等）。</p><hr><h2 id="_4-子系统关系" tabindex="-1">4. 子系统关系 <a class="header-anchor" href="#_4-子系统关系" aria-label="Permalink to &quot;4. 子系统关系&quot;">​</a></h2><h3 id="_4-1-config-配置" tabindex="-1">4.1 Config（配置） <a class="header-anchor" href="#_4-1-config-配置" aria-label="Permalink to &quot;4.1 Config（配置）&quot;">​</a></h3><ul><li><code>Config</code> 对象是运行时唯一配置入口，所有子系统从中读取参数</li><li><code>ConfigManager</code> 负责从磁盘加载、持久化和热更新</li><li>不允许子系统直接读取环境变量或配置文件，必须通过 <code>Config</code> 对象</li></ul><h3 id="_4-2-auth-认证" tabindex="-1">4.2 Auth（认证） <a class="header-anchor" href="#_4-2-auth-认证" aria-label="Permalink to &quot;4.2 Auth（认证）&quot;">​</a></h3><ul><li><code>AuthManager</code> 管理小米账号的两层认证状态（长期态 + 短期态）</li><li><code>auth.json</code> 是事实来源，重启后从磁盘恢复</li><li>认证恢复流程见 <code>docs/spec/auth_runtime_recovery.md</code></li></ul><h3 id="_4-3-device-设备" tabindex="-1">4.3 Device（设备） <a class="header-anchor" href="#_4-3-device-设备" aria-label="Permalink to &quot;4.3 Device（设备）&quot;">​</a></h3><ul><li><code>DeviceManager</code> 管理所有设备的生命周期</li><li>每个设备由一个 <code>DevicePlayer</code> 实例表示，持有设备侧连接</li><li>transport（mina/miio）由 <code>TransportRouter</code> 统一路由，不由 runtime 直接管理</li></ul><h3 id="_4-4-musiclibrary-音乐库" tabindex="-1">4.4 MusicLibrary（音乐库） <a class="header-anchor" href="#_4-4-musiclibrary-音乐库" aria-label="Permalink to &quot;4.4 MusicLibrary（音乐库）&quot;">​</a></h3><ul><li>持有本地音乐文件索引与歌单数据</li><li>是 <code>local_library</code> source 插件的数据来源</li><li>支持后台异步刷新，不阻塞播放</li></ul><h3 id="_4-5-playbackfacade-播放门面" tabindex="-1">4.5 PlaybackFacade（播放门面） <a class="header-anchor" href="#_4-5-playbackfacade-播放门面" aria-label="Permalink to &quot;4.5 PlaybackFacade（播放门面）&quot;">​</a></h3><ul><li>不由 runtime 直接持有，由 api 层通过 <code>_get_facade()</code> 按需获取</li><li>facade 通过 <code>runtime_provider</code> 获取 <code>XiaoMusic</code> 实例，间接使用 runtime 的子系统</li><li>状态快照构建（<code>build_player_state_snapshot</code>）由 facade 负责，runtime 不介入</li></ul><hr><h2 id="_5-runtime-不负责什么" tabindex="-1">5. Runtime 不负责什么 <a class="header-anchor" href="#_5-runtime-不负责什么" aria-label="Permalink to &quot;5. Runtime 不负责什么&quot;">​</a></h2><p>以下职责明确不在 runtime 边界内：</p><ul><li><strong>HTTP 路由</strong>：由 <code>api/routers/</code> 负责</li><li><strong>播放状态快照构建</strong>：由 <code>playback/facade.py</code> 的 <code>build_player_state_snapshot()</code> 负责</li><li><strong>revision / play_session_id 生成</strong>：由 <code>playback/facade.py</code> 的 <code>_compute_revision()</code> 负责</li><li><strong>SSE 事件推送</strong>：由 <code>api/routers/v1.py</code> 的 <code>_push_player_state_event()</code> 负责</li><li><strong>来源解析</strong>：由 source 层各 <code>SourcePlugin</code> 负责</li><li><strong>relay session 管理</strong>：由 <code>relay/</code> 边界自管理</li></ul><hr><h2 id="_6-相关文档" tabindex="-1">6. 相关文档 <a class="header-anchor" href="#_6-相关文档" aria-label="Permalink to &quot;6. 相关文档&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文档</th><th>职责</th></tr></thead><tbody><tr><td><code>docs/spec/runtime_specification.md</code></td><td>core 层数据模型、接口契约、错误体系的技术规范</td></tr><tr><td><code>docs/authentication_architecture.md</code></td><td>认证两层状态模型详细说明</td></tr><tr><td><code>docs/spec/auth_runtime_recovery.md</code></td><td>认证恢复流程规范</td></tr><tr><td><code>docs/architecture/system_overview.md</code></td><td>runtime 在系统九个一级边界中的位置</td></tr><tr><td><code>docs/spec/playback_coordinator_interface.md</code></td><td>PlaybackCoordinator 接口约束</td></tr></tbody></table>`,46)]))}const _=e(c,[["render",s]]);export{h as __pageData,_ as default};
